    for(int k=0; k<8; k++) t[k] = data[idx];

    size_t iterations = compute_iterations / 8;
    for (size_t j = 0; j < iterations; j++) {
      t[0] = t[0] * t[0] + f[0];
      t[1] = t[1] * t[1] + f[1];
      t[2] = t[2] * t[2] + f[2];
      t[3] = t[3] * t[3] + f[3];
      t[4] = t[4] * t[4] + f[4];
      t[5] = t[5] * t[5] + f[5];
      t[6] = t[6] * t[6] + f[6];
      t[7] = t[7] * t[7] + f[7];
    }

    if constexpr (compute_iterations % 8 > 0) {
      t[0] = t[0] * t[0] + f[0];
    }
    if constexpr (compute_iterations % 8 > 1) {
      t[1] = t[1] * t[1] + f[1];
    }
    if constexpr (compute_iterations % 8 > 2) {
      t[2] = t[2] * t[2] + f[2];
    }
    if constexpr (compute_iterations % 8 > 3) {
      t[3] = t[3] * t[3] + f[3];
    }
