template <typename Element, size_t compute_iterations>
size_t bench_cuda(size_t len, const Element seed1, const Element seed2, Element* src_device, Element* src_host) {
  constexpr size_t static_chunk_size = 4096;

  // Initialize data on host
  for(size_t i=0; i<len; i++) {
    src_host[i] = (i % 2 == 0) ? seed1 : seed2;
  }

  // Copy to device
  cudaMemcpy(src_device, src_host, len * sizeof(Element), cudaMemcpyHostToDevice);

  Element sum_host = 0;
  Element* sum_device;
  cudaMalloc(&sum_device, sizeof(Element));
  cudaMemcpy(sum_device, &sum_host, sizeof(Element), cudaMemcpyHostToDevice);

  int threads_per_block = 256;
  int blocks = (static_chunk_size + threads_per_block - 1) / threads_per_block;

  // Launch kernel for each chunk
  size_t total_chunks = (len + static_chunk_size - 1) / static_chunk_size;
  int total_blocks = total_chunks * blocks;

  bench_block_kernel<Element, compute_iterations, static_chunk_size><<<total_blocks, threads_per_block>>>(src_device, sum_device);

  cudaMemcpy(&sum_host, sum_device, sizeof(Element), cudaMemcpyDeviceToHost);

  *src_host = sum_host;

  cudaFree(sum_device);

  return len;
}

using benchmark_clock = std::chrono::steady_clock;

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = size / sizeof(double);
  auto timer_start = benchmark_clock::now();

  double* ptr_host = (double*)c;
  double* ptr_device;
  cudaMalloc(&ptr_device, num_elements * sizeof(double));

  bench_cuda<double, 16>(num_elements, 1., -1., ptr_device, ptr_host);

  cudaFree(ptr_device);

  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

template <typename Op>
auto benchmark_cuda(Op op) {
  constexpr int total_runs = 20;

  auto duration = op();  
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements            
            * compute_iterations_ 
            * 2                   
            * 1                   
        + total_elements - 1;     
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

