template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__global__ void bench_block_cuda(Element* data, Element* sum_out, size_t len) {
  Element sum = 0;
  Element f = data[0];

  size_t idx = blockIdx.x * static_chunk_size + threadIdx.x;
  if (idx < len) {
    Element t = data[idx];
    for (size_t j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    sum += t;
  }

  // Simple reduction within block (assuming 1 thread per block for simplicity or use atomic)
  // For exact reproduction of logic with parallelism, we map each thread to one element
  // and accumulate globally.
  if (idx < len) {
    atomicAdd(sum_out, sum);
  }
}

