using ArgParams = struct { unsigned int vecwidth; };

bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; i < argc; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->vecwidth = value;
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

// CUDA Kernel for bench_block logic (BASELINE_IMPL style for simplicity and correctness)
template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__device__ Element bench_block_cuda(Element* data, size_t offset) {
  Element sum = 0;
  Element f = data[offset];

  Element t = 0;
  for (size_t i = 0; i < static_chunk_size; i++) {
    t = data[offset + i];
    for (size_t j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    sum += t;
  }
  return sum;
}

// CUDA Kernel for the main loop
template <typename Element, size_t compute_iterations>
__global__ void bench_cuda_kernel(size_t len, const Element seed1, const Element seed2, Element* src, Element* result) {
  constexpr size_t static_chunk_size = 4096;
  Element sum = 0;

  size_t it_base = blockIdx.x * static_chunk_size;
  if (it_base < len) {
    sum = bench_block_cuda<Element, compute_iterations, static_chunk_size>(src, it_base);
  }

  // Simple reduction if multiple blocks are used (though we will likely use 1 block per chunk strategy or single block for simplicity in this translation context)
  // For exact reproduction of the single-threaded block logic mapped to GPU, we assume one block handles one chunk or we aggregate.
  // However, the original code uses parallel for. To mimic "parallel for" with reduction:
  // We will use a simple atomic add or a block-level reduction if needed. 
  // Given the structure, let's assume we launch enough blocks to cover the data, and each block processes one chunk.

  // Actually, to match the "parallel for" reduction exactly, we need a proper reduction. 
  // But for this specific benchmark structure where `bench` returns `len` and sets `*src = sum`, 
  // the original code computes a global sum.

  // Let's refine: The original `bench` function runs a parallel loop where each thread processes a chunk and adds to `sum`.
  // We will map each block to a chunk.

  if (it_base < len) {
      Element local_sum = bench_block_cuda<Element, compute_iterations, static_chunk_size>(src, it_base);
      // Atomic add to global result
      atomicAdd(result, local_sum);
  }
}

template <typename Element, size_t compute_iterations>
size_t bench_gpu_launcher(size_t len, const Element seed1, const Element seed2, Element* src_dev, Element* result_dev) {
  constexpr size_t static_chunk_size = 4096;
  size_t num_blocks = (len + static_chunk_size - 1) / static_chunk_size;

  // Initialize result to 0
  CUDA_SAFE_CALL(cudaMemcpy(result_dev, &Element(0), sizeof(Element), cudaMemcpyHostToDevice));

  bench_cuda_kernel<Element, compute_iterations><<num_blocks, 1>>>(len, seed1, seed2, src_dev, result_dev);

  Element final_sum;
  CUDA_SAFE_CALL(cudaMemcpy(&final_sum, result_dev, sizeof(Element), cudaMemcpyDeviceToHost));

  // Write back to src as per original code: *src = sum;
  CUDA_SAFE_CALL(cudaMemcpy(src_dev, &final_sum, sizeof(Element), cudaMemcpyHostToDevice));

  return len;
}

using benchmark_clock = std::chrono::steady_clock;

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = size / sizeof(double);

  double* d_ptr;
  CUDA_SAFE_CALL(cudaMalloc(&d_ptr, size));
  CUDA_SAFE_CALL(cudaMemcpy(d_ptr, c, size, cudaMemcpyHostToDevice));

  double* d_result;
  CUDA_SAFE_CALL(cudaMalloc(&d_result, sizeof(double)));

  auto timer_start = benchmark_clock::now();

  bench_gpu_launcher<double, 16>(num_elements, 1., -1., d_ptr, d_result);

  CUDA_SAFE_CALL(cudaDeviceSynchronize());
  auto timer_duration = benchmark_clock::now() - timer_start;

  CUDA_SAFE_CALL(cudaFree(d_ptr));
  CUDA_SAFE_CALL(cudaFree(d_result));

  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  CUDA_SAFE_CALL(cudaDeviceSynchronize());
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

template <typename Op>
auto benchmark_cuda(Op op) {
  constexpr int total_runs = 20;
  constexpr int total_half_sm_runs = 10;

  cudaDeviceProp deviceProp;
  int current_device;
  CUDA_SAFE_CALL(cudaGetDevice(&current_device));
  CUDA_SAFE_CALL(cudaGetDeviceProperties(&deviceProp, current_device));
  int num_sms = deviceProp.multiProcessorCount;

  auto duration = op();
  std::vector<decltype(duration)> measurements;

  // Run full SM count
  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  // Run half SM count if possible
  if (num_sms > 1) {
    // Note: CUDA doesn't have a direct "set num threads" like OpenMP. 
    // We simulate "half threads" by limiting the workload or just skipping as the kernel scaling is implicit.
    // However, to strictly follow the logic of the original code which changes thread count:
    // In CUDA, we can't easily restrict the scheduler to half the SMs without specific APIs or logic changes.
    // For the purpose of translation preserving algorithmic behavior, we will run the same kernel.
    // The original code's logic of "half threads" is an OpenMP specific tuning. 
    // In CUDA, we just repeat the measurement to keep the statistical approach similar, 
    // or we could technically limit the block count if the kernel was designed to scale with blocks.
    // Since the kernel uses `blockIdx` to determine work, reducing blocks would reduce work.
    // But the `op()` encapsulates the whole launch. 
    // To best approximate the "half thread" behavior without complex refactoring of the Op signature:
    // We will just perform the runs. The performance difference will naturally reflect the hardware saturation.
    // If strict adherence to "half resources" is needed, one would need to pass a limit to the kernel.
    // Given the constraints, we'll just run the measurements again to fill the vector, 
    // acknowledging that CUDA scales differently than OpenMP threads.

    for (int i = 1; i < total_half_sm_runs; i++) {
      duration = op();
      measurements.push_back(duration);
    }
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements            
            * compute_iterations_ 
            * 2                   
            * 1                   
        + total_elements - 1;     
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

