// CUDA version of mixbenchCPU
void mixbenchGPU(void* c_host, size_t size) {
  // Initialize memory on GPU
  void* d_c;
  CUDA_SAFE_CALL(cudaMalloc(&d_c, size));

  // Zero out the memory using a kernel or cudaMemcpy
  // Using a simple kernel to zero out
  size_t num_ints = size / sizeof(int);
  dim3 block(256);
  dim3 grid((num_ints + block.x - 1) / block.x);

  auto zero_kernel = [](int* data, size_t n) {
      __global__ void kernel(int* data, size_t n) {
          size_t idx = blockIdx.x * blockDim.x + threadIdx.x;
          if (idx < n) data[idx] = 0;
      }
      kernel<<<grid, block>>>(data, n);
  };

  // We need to define the kernel properly outside or use a lambda with global function
  // Let's use a direct cudaMemcpy for zeroing if host is already zero, or just launch a kernel.
  // The original code zeroes the passed pointer `c`. Here `c_host` is passed from main.
  // We assume `c_host` is the source. We copy to device and zero there.

  int* d_ints = (int*)d_c;
  __global__ void zero_ints_kernel(int* data, size_t n) {
      size_t idx = blockIdx.x * blockDim.x + threadIdx.x;
      if (idx < n) data[idx] = 0;
  }
  zero_ints_kernel<<<grid, block>>>(d_ints, num_ints);
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup(c_host, size);

  runbench_range<0, 1, 2, 3, 4, 6, 8, 12, 16, 20, 24, 28, 32, 40, 6 * 8, 7 * 8,
                 8 * 8, 10 * 8, 13 * 8, 15 * 8, 16 * 8, 20 * 8, 24 * 8, 32 * 8,
                 40 * 8, 64 * 8>(d_c, size);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;

  CUDA_SAFE_CALL(cudaFree(d_c));
}

